    21→// ─── Rate Limiting (in-memory) ──────────────────────────────────────────────
    22→const loginAttempts = new Map(); // ip -> { count, firstAttempt }
    23→const RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes
    24→const MAX_ATTEMPTS = 5;
    25→
    26→function checkRateLimit(ip) {
    27→  const now = Date.now();
    28→  const record = loginAttempts.get(ip);
    29→
    30→  if (!record || (now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    31→    loginAttempts.set(ip, { count: 1, firstAttempt: now });
    32→    return { allowed: true, remaining: MAX_ATTEMPTS - 1 };
    33→  }
    34→
    35→  if (record.count >= MAX_ATTEMPTS) {
    36→    const retryAfter = Math.ceil((RATE_LIMIT_WINDOW - (now - record.firstAttempt)) / 1000);
    37→    return { allowed: false, retryAfter };
    38→  }
    39→
    40→  record.count++;
    41→  return { allowed: true, remaining: MAX_ATTEMPTS - record.count };
    42→}
    43→
    44→// Clean up old rate limit entries every 30 minutes
    45→setInterval(() => {
    46→  const now = Date.now();
    47→  for (const [ip, record] of loginAttempts.entries()) {
    48→    if ((now - record.firstAttempt) > RATE_LIMIT_WINDOW) {
    49→      loginAttempts.delete(ip);
    50→    }
    51→  }
    52→}, 30 * 60 * 1000);
