    85→// ─── Middleware ──────────────────────────────────────────────────────────────
    86→function requireAdmin(req, res, next) {
    87→  // Path 1: Already authenticated via admin login
    88→  if (req.session && req.session.isAdmin) {
    89→    return next();
    90→  }
    91→
    92→  // Path 2: Bridge — JWT-authenticated user with admin role gets auto-elevated
    93→  const token = req.headers.authorization?.split(' ')[1] || (req.session && req.session.token);
    94→  if (token && verifyToken) {
    95→    const decoded = verifyToken(token);
    96→    if (decoded && decoded.role === 'admin') {
    97→      // Bridge: set admin session so subsequent requests don't re-verify
    98→      req.session.isAdmin = true;
    99→      req.session.adminLoginAt = new Date().toISOString();
   100→      req.session.adminBridgedFrom = decoded.email;
   101→      return next();
   102→    }
   103→  }
   104→
   105→  return res.status(401).json({ error: 'Admin authentication required' });
