   110→// POST /api/admin/login
   111→router.post('/login', async (req, res) => {
   112→  const ip = req.ip || req.connection.remoteAddress || 'unknown';
   113→  const rateCheck = checkRateLimit(ip);
   114→
   115→  if (!rateCheck.allowed) {
   116→    return res.status(429).json({
   117→      error: 'Too many login attempts',
   118→      retryAfter: rateCheck.retryAfter,
   119→      message: `Too many failed login attempts. Try again in ${Math.ceil(rateCheck.retryAfter / 60)} minutes.`,
   120→    });
   121→  }
   122→
   123→  const { username, password } = req.body;
   124→
   125→  if (!username || !password) {
   126→    return res.status(400).json({ error: 'Username and password required' });
   127→  }
   128→
   129→  // Wait for hash to be ready
   130→  if (!ADMIN_PASSWORD_HASH) {
   131→    return res.status(503).json({ error: 'Server initializing, try again in a moment' });
   132→  }
   133→
   134→  const usernameMatch = username === ADMIN_USERNAME;
   135→  const passwordMatch = await bcrypt.compare(password, ADMIN_PASSWORD_HASH);
   136→
   137→  if (!usernameMatch || !passwordMatch) {
   138→    logAuthEvent('admin_login_failed', null, username, ip, { reason: 'invalid_credentials' });
   139→    return res.status(401).json({ error: 'Invalid credentials' });
   140→  }
   141→
   142→  // Set admin session
   143→  req.session.isAdmin = true;
   144→  req.session.adminLoginAt = new Date().toISOString();
   145→
   146→  // Reset rate limiter on success
   147→  loginAttempts.delete(ip);
   148→
   149→  logAuthEvent('admin_login_success', null, ADMIN_USERNAME, ip);
   150→
   151→  return res.json({
   152→    success: true,
   153→    message: 'Admin login successful',
   154→    user: { username: ADMIN_USERNAME, role: 'admin' },
   155→  });
   156→});
