   158→// GET /api/admin/me
   159→router.get('/me', (req, res) => {
   160→  // Check direct admin session first
   161→  if (req.session && req.session.isAdmin) {
   162→    return res.json({
   163→      authenticated: true,
   164→      user: {
   165→        username: req.session.adminBridgedFrom || ADMIN_USERNAME,
   166→        role: 'admin',
   167→        loginAt: req.session.adminLoginAt,
   168→        bridged: !!req.session.adminBridgedFrom,
   169→      },
   170→    });
   171→  }
   172→
   173→  // Check JWT bridge: if user has admin role, auto-elevate
   174→  const token = req.headers.authorization?.split(' ')[1] || (req.session && req.session.token);
   175→  if (token && verifyToken) {
   176→    const decoded = verifyToken(token);
   177→    if (decoded && decoded.role === 'admin') {
   178→      req.session.isAdmin = true;
   179→      req.session.adminLoginAt = new Date().toISOString();
   180→      req.session.adminBridgedFrom = decoded.email;
   181→      return res.json({
   182→        authenticated: true,
   183→        user: {
   184→          username: decoded.email,
   185→          role: 'admin',
   186→          loginAt: req.session.adminLoginAt,
   187→          bridged: true,
   188→        },
   189→      });
   190→    }
   191→  }
   192→
   193→  return res.status(401).json({ authenticated: false });
   194→});
