   196→// POST /api/admin/bridge — auto-elevate JWT admin users without separate login
   197→router.post('/bridge', (req, res) => {
   198→  const token = req.headers.authorization?.split(' ')[1] || (req.session && req.session.token);
   199→  if (!token) {
