   210→  }
   211→
   212→  // Bridge the session
   213→  req.session.isAdmin = true;
   214→  req.session.adminLoginAt = new Date().toISOString();
   215→  req.session.adminBridgedFrom = decoded.email;
   216→
   217→  const ip = req.ip || req.connection.remoteAddress || 'unknown';
